// // This module implements a 2-to-1 multiplexer where the output selects 'b' when 's' is 0 and 'a' when 's' is 1.
module top_module(input a, input b, input s, output reg out);always @(*) begin
    if (s == 0) begin
        out = a;
    end else begin
        out = b;
    end
end

endmodule
